const VOCAB_STORAGE_KEY = "variant_saved_words";
const tierShuffleKey = (tier) => `variant_vocab_shuffle_${tier}`;
const tierIndexKey = (tier) => `variant_vocab_index_${tier}`;
function pickWordFisherYates(bank, tier) {
  const allWords = bank.map((e2) => e2.word);
  let shuffled;
  let index2;
  try {
    const rawShuffled = localStorage.getItem(tierShuffleKey(tier));
    const rawIndex = localStorage.getItem(tierIndexKey(tier));
    if (!rawShuffled || !rawIndex) {
      shuffled = fisherYatesShuffle(allWords);
      localStorage.setItem(tierShuffleKey(tier), JSON.stringify(shuffled));
      localStorage.setItem(tierIndexKey(tier), "0");
      index2 = 0;
    } else {
      shuffled = JSON.parse(rawShuffled);
      index2 = Number.parseInt(rawIndex, 10);
      if (shuffled.length !== allWords.length) {
        shuffled = fisherYatesShuffle(allWords);
        localStorage.setItem(tierShuffleKey(tier), JSON.stringify(shuffled));
        localStorage.setItem(tierIndexKey(tier), "0");
        index2 = 0;
      }
      if (index2 >= shuffled.length) {
        shuffled = fisherYatesShuffle(allWords);
        localStorage.setItem(tierShuffleKey(tier), JSON.stringify(shuffled));
        localStorage.setItem(tierIndexKey(tier), "1");
        index2 = 0;
      }
    }
    localStorage.setItem(tierIndexKey(tier), String(index2 + 1));
    const wordName = shuffled[index2];
    return bank.find((e2) => e2.word === wordName) ?? bank[Math.floor(Math.random() * bank.length)];
  } catch {
    return bank[Math.floor(Math.random() * bank.length)];
  }
}
function getSavedWords() {
  try {
    const raw = localStorage.getItem(VOCAB_STORAGE_KEY);
    if (!raw) return [];
    return JSON.parse(raw);
  } catch {
    return [];
  }
}
function saveWord(w2) {
  const existing = getSavedWords();
  if (existing.some((s2) => s2.id === w2.id)) return;
  existing.push(w2);
  localStorage.setItem(VOCAB_STORAGE_KEY, JSON.stringify(existing));
}
function deleteSavedWord(id2) {
  const existing = getSavedWords().filter((s2) => s2.id !== id2);
  localStorage.setItem(VOCAB_STORAGE_KEY, JSON.stringify(existing));
}
function getDifficultyLabel(d2) {
  if (d2 <= 3) return "Beginner";
  if (d2 <= 6) return "Intermediate";
  if (d2 <= 8) return "Advanced";
  return "Professional";
}
function shuffleArray(arr) {
  const a2 = [...arr];
  for (let i2 = a2.length - 1; i2 > 0; i2--) {
    const j2 = Math.floor(Math.random() * (i2 + 1));
    [a2[i2], a2[j2]] = [a2[j2], a2[i2]];
  }
  return a2;
}
